(function () {
  function parseParams(hash) {
    var query = hash.split("?")[1] || "";
    var params = {};
    query.split("&").forEach(function (part) {
      if (!part) return;
      var pair = part.split("=");
      var key = decodeURIComponent(pair[0]);
      var val = decodeURIComponent(pair[1] || "");
      params[key] = val;
    });
    return params;
  }

  // Match numbers that may include thousands separators, e.g. 5,000 or 12,345.67
  function extractNumbers(text) {
    var re = /-?\d{1,3}(?:,\d{3})*(?:\.\d+)?/g;
    var matches = [];
    var m;
    while ((m = re.exec(text)) !== null) {
      var raw = m[0];                         // e.g. "5,000"
      var normalized = raw.replace(/,/g, ""); // "5000"
      matches.push({
        raw: raw,
        value: parseFloat(normalized),
        decimals: (normalized.split(".")[1] || "").length
      });
    }
    return matches;
  }

  function formatWithCommas(num, decimals) {
    var n = Number(num);
    if (!isFinite(n)) n = 0;
    return n.toLocaleString(undefined, {
      minimumFractionDigits: decimals,
      maximumFractionDigits: decimals
    });
  }

  function animateCounts(el, options) {
    if (el.__glsCountAnimating || el.__glsCountDone) return;
    el.__glsCountAnimating = true;

    var fullText = el.textContent;
    var nums = extractNumbers(fullText);

    if (!nums.length) {
      el.__glsCountAnimating = false;
      el.__glsCountDone = true;
      return;
    }

    var duration = options.duration || 2000;
    var startTime = null;

    // If you pass start/end params, they apply to EACH number found.
    // Otherwise, each number animates from 0 to its original value.
    var perNumber = nums.map(function (n) {
      var end = (typeof options.end === "number") ? options.end : n.value;
      var start = (typeof options.start === "number") ? options.start : 0;
      var decimals =
        (typeof options.decimals === "number") ? options.decimals : n.decimals;

      return { start: start, end: end, decimals: decimals };
    });

    // Same regex used for replace, ensuring commas are treated as part of the number
    var replaceRe = /-?\d{1,3}(?:,\d{3})*(?:\.\d+)?/g;

    function step(ts) {
      if (!startTime) startTime = ts;
      var progress = Math.min((ts - startTime) / duration, 1);

      var i = 0;
      el.textContent = fullText.replace(replaceRe, function () {
        var n = perNumber[i++];
        if (!n) return "";

        var current = n.start + (n.end - n.start) * progress;

        // Keep decimals stable, then add commas back
        var fixed = current.toFixed(n.decimals);
        return formatWithCommas(fixed, n.decimals);
      });

      if (progress < 1) {
        requestAnimationFrame(step);
      } else {
        el.__glsCountAnimating = false;
        el.__glsCountDone = true;
      }
    }

    requestAnimationFrame(step);
  }

  function initCounts() {
    var links = document.querySelectorAll('a[href^="#gls-count"]');
    if (!links.length) return;

    var supportsIO = "IntersectionObserver" in window;

    var observer = supportsIO
      ? new IntersectionObserver(function (entries) {
          entries.forEach(function (entry) {
            if (entry.isIntersecting) {
              var link = entry.target;
              animateCounts(link, link.__glsCountOptions || {});
              observer.unobserve(link);
            }
          });
        }, { threshold: 0.2 })
      : null;

    links.forEach(function (link) {
      var href = link.getAttribute("href") || "";
      var params = parseParams(href);

      var opts = {};
      if (params.start) opts.start = parseFloat(params.start);
      if (params.end) opts.end = parseFloat(params.end);
      if (params.duration) opts.duration = parseInt(params.duration, 10);
      if (params.decimals) opts.decimals = parseInt(params.decimals, 10);

      link.__glsCountOptions = opts;

      // prevent jumping to the hash
      link.addEventListener("click", function (e) {
        e.preventDefault();
      });

      if (supportsIO && observer) observer.observe(link);
      else animateCounts(link, opts);
    });
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", initCounts);
  } else {
    initCounts();
  }
})();
